template <typename Element>
struct BiasGemmPolicySelector {
  using Policy = Sm80TensorOp256x128x16S3W4x2x1TF32F32GemmPolicy;
};

template <>
struct BiasGemmPolicySelector<cutlass::half_t> {
  using Policy = Sm80TensorOp256x128x32S3W4x2x1F16F32GemmPolicy;
};

template <>
struct BiasGemmPolicySelector<cutlass::bfloat16_t> {
  using Policy = Sm80TensorOp256x128x32S3W4x2x1F16F32GemmPolicy;
};

template <typename Element>
using BiasGemmPolicy = typename BiasGemmPolicySelector<Element>::Policy;

template <typename Storage, typename Element, typename LayoutB, typename EpilogueOp, typename Policy = BiasGemmPolicy<Element>>
int launch_gemm_bias(
    Storage const* a,
    Storage const* b,
    Storage const* bias,
    Storage* c,
    int m,
    int n,
    int k,
    int ldb,
    cudaStream_t stream) {
  if (a == nullptr || b == nullptr || bias == nullptr || c == nullptr) {
    return 1;
  }
  if (m <= 0 || n <= 0 || k <= 0) {
    return 2;
  }
  using Gemm = cutlass::gemm::device::Gemm<
      Element,
      cutlass::layout::RowMajor,
      Element,
      LayoutB,
      Element,
      cutlass::layout::RowMajor,
      typename Policy::ElementAccumulator,
      typename Policy::OperatorClass,
      typename Policy::ArchTag,
      typename Policy::ThreadblockShape,
      typename Policy::WarpShape,
      typename Policy::InstructionShape,
      EpilogueOp,
      cutlass::gemm::threadblock::GemmIdentityThreadblockSwizzle<>,
      Policy::kStages>;
  Gemm gemm;
  typename Gemm::Arguments args(
      {m, n, k},
      {cutlass_ptr<Storage, Element>(a), k},
      {cutlass_ptr<Storage, Element>(b), ldb},
      {cutlass_ptr<Storage, Element>(bias), 0},
      {cutlass_ptr<Storage, Element>(c), n},
      typename EpilogueOp::Params(1.0f));
  cutlass::Status status = gemm(args, nullptr, stream);
  return status == cutlass::Status::kSuccess ? 0 : 3;
}

template <typename Storage, typename Element, typename LayoutB, typename EpilogueOp, typename Policy = BiasGemmPolicy<Element>>
int launch_gemm_bias_residual(
    Storage const* a,
    Storage const* b,
    Storage const* bias,
    Storage const* d0,
    Storage const* d1,
    Storage* c,
    int m,
    int n,
    int k,
    int ldb,
    cudaStream_t stream) {
  if (a == nullptr || b == nullptr || bias == nullptr || d0 == nullptr || c == nullptr) {
    return 1;
  }
  if constexpr (!EpilogueOp::kIsSingleSource) {
    if (d1 == nullptr) {
      return 1;
    }
  }
  if (m <= 0 || n <= 0 || k <= 0) {
    return 2;
  }
  using Gemm = cutlass::gemm::device::GemmUniversalWithBroadcast<
      Element,
      cutlass::layout::RowMajor,
      Element,
      LayoutB,
      Element,
      cutlass::layout::RowMajor,
      typename Policy::ElementAccumulator,
      typename Policy::OperatorClass,
      typename Policy::ArchTag,
      typename Policy::ThreadblockShape,
      typename Policy::WarpShape,
      typename Policy::InstructionShape,
      EpilogueOp,
      cutlass::gemm::threadblock::GemmIdentityThreadblockSwizzle<>,
      Policy::kStages>;
  Gemm gemm;
  if constexpr (EpilogueOp::kIsSingleSource) {
    typename Gemm::Arguments args(
        cutlass::gemm::GemmUniversalMode::kGemm,
        {m, n, k},
        1,
        typename EpilogueOp::Params(1.0f),
        cutlass_ptr<Storage, Element>(a),
        cutlass_ptr<Storage, Element>(b),
        cutlass_ptr<Storage, Element>(d0),
        cutlass_ptr<Storage, Element>(c),
        const_cast<Element*>(cutlass_ptr<Storage, Element>(bias)),
        nullptr,
        static_cast<int64_t>(m) * k,
        static_cast<int64_t>(n) * k,
        static_cast<int64_t>(m) * n,
        static_cast<int64_t>(m) * n,
        0,
        static_cast<int64_t>(m) * n,
        k,
        ldb,
        n,
        n,
        0,
        n);
    cutlass::Status status = gemm(args, nullptr, stream);
    return status == cutlass::Status::kSuccess ? 0 : 3;
  } else {
    typename Gemm::Arguments args(
        cutlass::gemm::GemmUniversalMode::kGemm,
        {m, n, k},
        1,
        typename EpilogueOp::Params(1.0f),
        cutlass_ptr<Storage, Element>(a),
        cutlass_ptr<Storage, Element>(b),
        cutlass_ptr<Storage, Element>(d0),
        cutlass_ptr<Storage, Element>(d1),
        cutlass_ptr<Storage, Element>(c),
        const_cast<Element*>(cutlass_ptr<Storage, Element>(bias)),
        nullptr,
        static_cast<int64_t>(m) * k,
        static_cast<int64_t>(n) * k,
        static_cast<int64_t>(m) * n,
        static_cast<int64_t>(m) * n,
        static_cast<int64_t>(m) * n,
        0,
        static_cast<int64_t>(m) * n,
        k,
        ldb,
        n,
        n,
        n,
        0,
        n);
    cutlass::Status status = gemm(args, nullptr, stream);
    return status == cutlass::Status::kSuccess ? 0 : 3;
  }
}

template <typename Storage, typename Element, typename LayoutB>
float profile_gemm(
    Storage const* a,
    Storage const* b,
    Storage* c,
    int m,
    int n,
    int k,
    int ldb,
    int iterations,
    cudaStream_t stream) {
  if (iterations <= 0) {
    iterations = 20;
  }
  cudaEvent_t start;
  cudaEvent_t end;
  cudaEventCreate(&start);
  cudaEventCreate(&end);
  launch_gemm<Storage, Element, LayoutB>(a, b, c, m, n, k, ldb, stream);
  cudaEventRecord(start, stream);
  for (int i = 0; i < iterations; ++i) {
    launch_gemm<Storage, Element, LayoutB>(a, b, c, m, n, k, ldb, stream);
  }
  cudaEventRecord(end, stream);
  cudaEventSynchronize(end);
  float ms = 0.0f;
  cudaEventElapsedTime(&ms, start, end);
  cudaEventDestroy(start);
  cudaEventDestroy(end);
  return ms / static_cast<float>(iterations);
}

template <typename Storage, typename Element, typename LayoutB, typename Policy>
float profile_gemm_policy(
    Storage const* a,
    Storage const* b,
    Storage* c,
